window.SITE_LOCALES = {"en":{"lang":"en","meta":{"title":"Not A Translator - Native-language definitions inside the page","description":"Native-language definitions, audio, unit and timezone conversions, smarter lookup routes and console mode for difficult pages."},"shared":{"appName":"Not A Translator","lookup":"Get meaning for","consoleMode":"Console mode","tooltipMode":"Tooltip mode","contribute":"Contribute","dictionary":"Dictionary","badges":{"risky":"risky","conditional":"works under conditions","ok":"ok"},"console":{"copy":"Copy","remove":"Remove","forceForSite":"Force console for this site"},"languages":{"english":"English","spanish":"Spanish","french":"French","german":"German","italian":"Italian","finnish":"Finnish","ancient":"Latin + Greek (translation)"}},"site":{"languageLabel":"Language","brandTagline":"Definitions stay in the text flow.","nav":{"features":"Features","updates":"Updates","engine":"Engine","usage":"Usage","faq":"FAQ"},"hero":{"eyebrow":"Read first. Translate later.","title":"Keep the definition inside the page, in the language that owns the word.","lead":"Not A Translator injects lightweight tooltips near your selection, keeps the original-language definition front and center, and hides a lot of technical work behind a very simple gesture.","primaryCta":"See features","secondaryCta":"Usage","storeCtas":{"install":"","chrome":"Chrome","firefoxAndroid":"Ffox Android","firefox":"Firefox","paypal":"PayPal Me","paypalLabel":""},"panelNote":"Console mode stores entries when a page resists tooltip rendering.","status":{"published":{"kicker":"Published now","title":"Available on Chrome, Firefox and Firefox Android.","body":"The application is already distributed on the main current platforms."},"funding":{"kicker":"Safari Extension","title":"The Safari port is in development, but needs funding to reach publication on the Apple Store.","body":"The code migration exists, the browser-specific work is done, and funding would help cross the final step.","cta":"Support development"}},"points":["Definitions stay in the source language instead of breaking reading with a generic translation detour. no new tab to break your reading. no language swap to interrupt your understanding","Audio, translate-anyway, repair and open-page actions stay one click away inside the tooltip or console entry.","A lot happens behind the scenes: lookup retries, candidate routing, fallback providers and per-site safeguards, detection of the languages involved, and detection of pages that resist injection."],"inlineDemo":{"before":"Not A Translator injects lightweight ","word":"tooltips","badge":"rotating","definition":"(noun) floating definition boxes that stay close to the selection and can rotate around it to escape edges and overlap.","after":" near your selection, keeps the source-language definition as close as possible to the text without disturbing your understanding, and hides a lot of technical complexity behind a very simple gesture."}},"demo":{"word":"epoch","time":"09:58:47","definition":"(noun) a long period of time, especially one marked by distinctive events or development."},"signals":{"items":[{"value":"3 published builds","label":"Live today","body":"Chrome, Firefox desktop and Firefox Android are the currently published extensions."},{"value":"Console mode","label":"For difficult pages","body":"When a page fights tooltip rendering, stored definitions move into a controlled side console."},{"value":"Search smarter","label":"Behind the tooltip","body":"Candidate rescue, multi-word lookup and compound handling quietly improve the visible result."}]},"manifesto":{"eyebrow":"Why it feels different","title":"A reading-first workflow.","lead":"The extension is designed to keep the page at the center of the experience: define in place, translate only when necessary, and stay readable even when injection gets difficult.","items":[{"title":"Definition before translation","body":"The extension is designed to preserve the idea that a word is often understood more intuitively when its definition is given first in its own language."},{"title":"The page stays the main surface","body":"Tooltip, quick translate, audio and open-page actions stay close to the selection so reading does not immediately turn into tab switching. You keep the thread!"},{"title":"When a page fights back, the result should survive","body":"Some sites are hostile to inline injections or simply unstable. Console mode exists so the essential part, the stored definition, remains available instead of disappearing with the tooltip. In the worst case, F5/refresh will restore the page to its initial state. No change is permanent at this level."}]},"screenshots":{"eyebrow":"In context","title":"The extension is meant to live inside real reading situations.","lead":"A desktop Firefox view and a mobile Safari development view help make that concrete.","desktop":{"title":"Firefox desktop","body":"Tooltip near the selected word, popup controls, and the original reading flow preserved."},"mobile":{"title":"Safari iPhone development build","body":"A portable layout where the tooltip stays compact and readable inside a mobile page."}},"features":{"eyebrow":"Core features","title":"Simple on the surface, dense underneath.","lead":"One selection can trigger dictionary routing, backup searches, definitions of new candidates on variant forms, audio sourcing, conversion parsing, timezone interpretation and, on hostile pages, a controlled shift into console mode.","items":[{"title":"Native-language definitions","body":"The main path is still the same idea: select a word and get its definition in the language it belongs to, so reading and language learning stay connected."},{"title":"Conversions and timezone helpers","body":"Numeric selections can switch into conversion mode, including unit conversions and timezone-aware time conversion without leaving the page."},{"title":"Audio close to the selection","body":"When pronunciation is available, the tooltip or console entry can expose audio directly, using the best source available. the icon indicates whether the voice is human or synthetic"},{"title":"Console mode for hostile pages","body":"The repair action now opens console mode directly. all other repairs are handled automatically upstream. When inline rendering is unreliable, stored entries stay readable in a controlled panel instead of being lost."},{"title":"Smarter search routes","body":"Lookup now leans on better candidate routing: exact form first, then rescued candidates, multi-word expression handling, and lemma or compound strategies where useful."},{"title":"Lots of technique, quietly","body":"Quick translate now swaps the definition directly inside the tooltip. Behind that are fallback providers, per-site safeguards, mobile positioning work and browser-specific workarounds meant to keep the interaction short."}]},"updates":{"eyebrow":"Recent improvements","title":"Latest work now reflected on the extension site.","lead":"The landing page now describes the current state of the project instead of an older snapshot.","items":[{"kicker":"Conversion","title":"Thousands-aware numeric parsing","body":"Selections such as \"12,333 feet\" and even \"12,333,425 feet\" are now interpreted as grouped thousands instead of decimal numbers."},{"kicker":"Time","title":"Timezone conversion stays part of the same gesture","body":"Time selections can switch to a dedicated tooltip when a timezone is recognized, instead of forcing a separate workflow."},{"kicker":"Dictionary","title":"Finnish joins the active dictionary set","body":"Finnish support is now part of the live lineup, including dictionary access, menu exposure and the related audio / lookup plumbing."},{"kicker":"Lookup","title":"New search paths behind the tooltip","body":"Recent lookup work improves candidate rescue for English multi-word expressions and adds stronger compound handling for Finnish when direct lookup is not enough."}]},"engine":{"eyebrow":"Under the hood","title":"Much more happens than the interface lets on.","lead":"The extension is intentionally light in appearance and busy in the background.","items":[{"title":"Candidate routing","body":"A lookup does not stop at one raw form. The engine can retry exact forms, rescued variants and multi-word candidates before giving up."},{"title":"Conversions that read real text","body":"The conversion path now treats grouped thousands more safely and can switch between unit and timezone interpretation from the same selection."},{"title":"Console fallback","body":"The repair control now acts as a real mode switch: it sends the current lookup into console mode instead of only trying cosmetic recovery."},{"title":"Audio sourcing","body":"Pronunciation can come from Wiktionary, Commons, DWDS or a generated fallback depending on dictionary and availability."},{"title":"Finnish-specific work","body":"Finnish lookup is not just another menu entry: it includes extra dictionary routing and compound-aware strategies behind the scenes."},{"title":"Per-site reliability hints","body":"The badge is there to communicate confidence, not only language. Restricted or hostile pages should not look deceptively safe."},{"title":"Smartphone compatibility","body":"The presentation site now keeps the same hierarchy on small screens: stacked actions, stretch buttons and readable cards instead of a squeezed desktop layout."}]},"usage":{"eyebrow":"Usage","title":"A short gesture that tries to preserve reading.","lead":"The extension tries to keep context, avoid unnecessary navigation and degrade gracefully when a page interferes with injection.","steps":["Select a word or expression in the page you are reading.","Use the extension action or context menu to request the definition.","Read the tooltip near the selection and stay inside the page for definition, audio, quick translate or open-page follow-up.","If site detection proposes console mode, answer OK to switch. You can also click repair, the tool icon inside a tooltip, to send that lookup to the console.","Console mode keeps the stored entries in a stable side panel when inline rendering becomes unreliable.","To set tooltip color and opacity, or disable automatic language detection, open the extension popup: it exposes the current color, the available palette, the opacity slider and the language autodetect switch."]},"platforms":{"title":"Platforms","items":["Published: Firefox desktop","Published: Chrome desktop","Published: Firefox Android","Safari is under active development and needs funding to reach publication."]},"dictionaries":{"title":"Dictionaries","items":["English - Merriam-Webster Learner's Dictionary","Spanish - Diccionario de la Lengua Espa�f±ola","French - Larousse","German - DWDS","Italian - De Mauro Internazionale","Finnish - Kielitoimiston sanakirja / Wiktionary fallback","Latin + Greek - translation-oriented ancient-language route"]},"faq":{"eyebrow":"FAQ","title":"A few things worth saying clearly.","items":[{"q":"Is this a machine-translation extension?","a":"No. Translation exists as an optional fallback. The primary idea is still to expose the original-language definition first."},{"q":"Why is console mode important?","a":"Because some pages interfere with inline DOM injections. You can switch to it either by accepting the extension's detection prompt or by clicking repair, the tool icon inside a tooltip. Console mode then keeps the useful part, the stored definitions, even when the page is difficult."},{"q":"Can tooltip appearance be adjusted?","a":"Yes. In the extension popup, you can choose tooltip color, adjust opacity with the dedicated slider, and disable automatic language detection when you prefer to keep control over the active dictionary."},{"q":"Does it do a lot behind the scenes?","a":"Yes, but on purpose. Provider fallback, smarter lookup candidates, audio routing, conversion heuristics and browser-specific workarounds are there so the visible gesture stays simple."},{"q":"Will it work everywhere?","a":"Almost everywhere, but not on browser-restricted pages such as extension stores or other privileged browser surfaces where content scripts are blocked by the browser itself."}]},"footer":"No ads, no trackers, a lot of care, and many browser-specific edge cases handled transparently."}},"fr":{"lang":"fr","meta":{"title":"Not A Translator - Définitions en langue d'origine dans la page","description":"Définitions en langue source, audio, conversions d'unités et de fuseaux, recherches plus intelligentes et mode console pour les pages difficiles."},"shared":{"appName":"Not A Translator","lookup":"Rechercher le sens de","consoleMode":"Mode console","tooltipMode":"Mode infobulle","contribute":"Contribuer","dictionary":"Dictionnaire","badges":{"risky":"hasardeux","conditional":"sous conditions","ok":"ok"},"console":{"copy":"Copier","remove":"Supprimer","forceForSite":"Forcer la console pour ce site"},"languages":{"english":"Anglais","spanish":"Espagnol","french":"Français","german":"Allemand","italian":"Italien","finnish":"Finnois","ancient":"Latin + grec (traduction)"}},"site":{"languageLabel":"Langue","brandTagline":"Les définitions restent dans le flux de lecture.","nav":{"features":"Fonctions","updates":"Nouveautés","engine":"Moteur","usage":"Utilisation","faq":"FAQ"},"hero":{"eyebrow":"Lire d'abord. Traduire ensuite si besoin.","title":"Garder la définition dans la page, dans la langue du mot lui-même.","lead":"Not A Translator injecte des infobulles légères près de la sélection, met la définition d'origine au premier plan et cache beaucoup de technique derrière un geste très simple.","inlineDemo":{"before":"Not A Translator injecte des ","word":"infobulles","badge":"rotatives","definition":"(nom) boîtes de définition flottantes qui restent près de la sélection et peuvent tourner autour d'elle pour échapper aux bords et aux chevauchements.","after":" légères près de votre sélection, garde la définition dans la langue d'origine au plus près du texte, sans perturber votre compréhension et cache beaucoup de technicité derrière un geste très simple."},"primaryCta":"Voir les fonctionnalités","secondaryCta":"Usage","storeCtas":{"install":"","chrome":"Chrome","firefoxAndroid":"Ffox Android","firefox":"Firefox","paypal":"PayPal Me","paypalLabel":""},"panelNote":"Le mode console conserve les entrées quand une page résiste au rendu des infobulles.","status":{"published":{"kicker":"Publié maintenant","title":"Disponible sur Chrome, Firefox et Firefox Android.","body":"L'application est déjà distribuée sur les principales plateformes actuelles"},"funding":{"kicker":"Extension Safari","title":"Le portage Safari est en développement, mais a besoin de financements pour aller jusqu'à la publication sur Apple store.","body":"La migration du code existe, le travail spécifique au navigateur est fait, et un financement aiderait à franchir la dernière étape.","cta":"Soutenir le développement"}},"points":["Les définitions restent dans la langue source au lieu de casser la lecture avec un détour de traduction générique.","Audio, traduire quand même, réparation et ouverture de page restent accessibles directement dans l'infobulle ou l'entrée console.","Beaucoup de choses se passent en coulisses : reprises de recherche, routage de candidats, fournisseurs de secours et garde-fous par site, détection des langues impliquées, des pages réfractaires aux injections."]},"demo":{"word":"epoch","time":"09:58:47","definition":"(nom) longue période de temps, surtout marquée par des événements ou un développement particulier."},"signals":{"items":[{"value":"3 builds publiés","label":"Disponibles aujourd'hui","body":"Chrome, Firefox desktop et Firefox Android sont les extensions actuellement publiées."},{"value":"Mode console","label":"Pour les pages difficiles","body":"Quand une page contrarie le rendu des infobulles, les définitions stockées basculent dans une console latérale maîtrisée."},{"value":"Recherche plus fine","label":"Derrière l'infobulle","body":"Secours de multiples lemmes candidats, fallbacks, expressions multi-mots et gestion des composés améliorent discrètement le résultat visible."}]},"manifesto":{"eyebrow":"Pourquoi l'expérience diffère","title":"Un parcours lecture d'abord.","lead":"L'extension est conçue pour laisser la page au centre de l'expérience : définir sur place, traduire seulement si nécessaire, et rester lisible même quand l'injection devient difficile.","items":[{"title":"La définition avant la traduction","body":"L'extension est pensée pour préserver l'idée qu'un mot se comprend souvent plus intuitivement quand sa définition est donnée d'abord dans sa propre langue."},{"title":"La page reste la surface principale","body":"Infobulle, quick translate, audio et ouverture de page restent près de la sélection pour éviter que la lecture ne se transforme immédiatement en navigation entre onglets. On garde le fil!"},{"title":"Quand la page résiste, le résultat doit survivre","body":"Certaines pages sont hostiles aux injections inline ou simplement instables. Le mode console existe pour que l'essentiel, la définition stockée, reste disponible au lieu de disparaître avec l'infobulle. Dans le pire des cas F5/refresh remettra la page dans son état initial. Aucune modification n'est permanente à ce niveau."}]},"screenshots":{"eyebrow":"En situation","title":"L'extension est faite pour vivre dans de vraies situations de lecture.","lead":"Une vue Firefox desktop et une vue Safari iPhone en développement rendent cela plus concret.","desktop":{"title":"Firefox desktop","body":"Infobulle près du mot sélectionné, contrôles du popup et flux de lecture d'origine préservé."},"mobile":{"title":"Build Safari iPhone en développement","body":"Une mise en page portable où l'infobulle reste compacte et lisible à l'intérieur d'une page mobile."}},"features":{"eyebrow":"Fonctions clés","title":"Simple en surface, dense en profondeur.","lead":"Une seule sélection peut déclencher du routage de dictionnaires, des recherches de secours, des définitions de nouveaux candidats sur des formes à variantes, du sourcing audio, du parsing de conversions, de l'interprétation de fuseaux horaires et, sur les pages hostiles, une bascule maîtrisée vers le mode console.","items":[{"title":"Définitions en langue d'origine","body":"Le principe reste le même : sélectionner un mot et obtenir sa définition dans sa propre langue, pour garder lecture et apprentissage liés."},{"title":"Conversions et fuseaux horaires","body":"Les sélections numériques peuvent basculer en mode conversion, y compris pour les unités et les heures avec fuseau reconnu, sans quitter la page."},{"title":"Audio au plus près de la sélection","body":"Quand une prononciation existe, l'infobulle ou l'entrée console peut l'exposer directement en choisissant la meilleure source disponible. l’icône indique si la voix est humaine ou synthétique"},{"title":"Mode console pour les pages hostiles","body":"Le clic sur l'action repair ouvre maintenant directement le mode console. toutes les autres réparations sont traitées automatiquement en amont. Quand le rendu inline devient peu fiable, les entrées restent lisibles dans un panneau maîtrisé au lieu d'être perdues."},{"title":"Parcours de recherche plus intelligents","body":"Les recherches s'appuient désormais sur un routage de candidats plus robuste : forme exacte d'abord, puis secours de multiples lemmes candidats, fallbacks, expressions multi-mots et stratégies de lemme ou de composé quand c'est utile."},{"title":"Beaucoup de technique, discrètement","body":"Quick translate remplace maintenant la définition directement dans l'infobulle. Derrière cela se trouvent des fournisseurs de repli, des garde-fous par site, du travail de positionnement mobile et des contournements spécifiques aux navigateurs pour garder un geste court."}]},"updates":{"eyebrow":"Améliorations récentes","title":"Le site reflète maintenant l'état réel de l'extension.","lead":"La page de présentation décrit enfin la version actuelle au lieu d'un ancien instantané.","items":[{"kicker":"Conversion","title":"Lecture correcte des grands nombres","body":"Des sélections comme « 12,333 feet » ou même « 12,333,425 feet » sont maintenant interprétées comme des milliers groupés, et non comme des décimaux."},{"kicker":"Heure","title":"Les fuseaux restent dans le même geste","body":"Une sélection horaire peut ouvrir une infobulle dédiée quand un fuseau est reconnu, au lieu d'imposer un parcours séparé."},{"kicker":"Dictionnaire","title":"Le finnois rejoint l'ensemble actif","body":"Le finnois fait désormais partie de la gamme vivante, avec dictionnaire, menu, i18n et plomberie audio / recherche associée."},{"kicker":"Recherche","title":"Nouveaux modes de recherche sous le capot","body":"Le travail récent améliore le secours sur expressions anglaises multi-mots et ajoute une gestion plus solide des composés finnois quand la recherche directe ne suffit pas."}]},"engine":{"eyebrow":"Sous le capot","title":"Il se passe bien plus de choses que l'interface ne le laisse voir.","lead":"L'extension est volontairement légère en apparence et très active en arrière-plan.","items":[{"title":"Routage des candidats","body":"Une recherche ne s'arrête pas à une forme brute. Le moteur peut retenter des formes exactes, des variantes de secours et des candidats multi-mots avant d'abandonner."},{"title":"Conversions qui lisent du vrai texte","body":"Le parcours de conversion traite maintenant plus sûrement les milliers groupés et peut arbitrer entre unité et fuseau horaire à partir d'une même sélection."},{"title":"Repli console","body":"Le contrôle repair agit maintenant comme un vrai changement de mode : il envoie la recherche en cours vers le mode console au lieu d'une simple tentative cosmétique."},{"title":"Sourcing audio","body":"La prononciation peut venir de Wiktionary, Commons, DWDS ou d'un secours généré selon le dictionnaire et la disponibilité."},{"title":"Travail spécifique au finnois","body":"Le finnois n'est pas qu'une entrée de menu supplémentaire : il apporte un routage de dictionnaires et des stratégies orientées composés derrière la scène."},{"title":"Indice de fiabilité par site","body":"La pastille ne sert pas seulement à afficher une langue. Elle doit aussi communiquer la confiance, y compris sur les pages restreintes ou hostiles."},{"title":"Compatibilité smartphone","body":"Le site de présentation garde maintenant la même hiérarchie sur petit écran : actions empilées, boutons pleine largeur et cartes lisibles au lieu d'un desktop écrasé."}]},"usage":{"eyebrow":"Utilisation","title":"Un geste court qui essaie de préserver la lecture.","lead":"L'extension cherche à garder le contexte, à éviter les détours inutiles et à se dégrader proprement quand une page perturbe l'injection.","steps":["Sélectionnez un mot ou une expression dans la page que vous lisez.","Utilisez l'action de l'extension ou le menu contextuel pour demander la définition.","Lisez l'infobulle près de la sélection et restez dans la page pour la définition, l'audio, quick translate ou l'ouverture de page si besoin.","Si la détection du site vous propose le mode console, répondez OK pour y basculer. Vous pouvez aussi cliquer sur repair, l'icône outil dans un tooltip, pour envoyer cette recherche vers la console.","Le mode console conserve les entrées stockées dans un panneau latéral stable quand le rendu inline devient peu fiable.","Pour régler la couleur et l'opacité des tooltips, ou désactiver la détection automatique de langue, ouvrez le popup de l'extension : vous y trouverez la couleur courante, la palette disponible, le curseur d'opacité et le commutateur de détection de langue."]},"platforms":{"title":"Plateformes","items":["Publié : Firefox desktop","Publié : Chrome desktop","Publié : Firefox Android","Safari est en développement actif et a besoin de financements pour aller jusqu'à la publication."]},"dictionaries":{"title":"Dictionnaires","items":["Anglais - Merriam-Webster Learner's Dictionary","Espagnol - Diccionario de la Lengua Española","Français - Larousse","Allemand - DWDS","Italien - De Mauro Internazionale","Finnois - Kielitoimiston sanakirja avec repli Wiktionary","Latin + grec - parcours orienté traduction pour les langues anciennes"]},"faq":{"eyebrow":"FAQ","title":"Quelques points à dire clairement.","items":[{"q":"Est-ce une extension de traduction automatique ?","a":"Non. La traduction existe en secours facultatif. L'idée principale reste d'exposer d'abord la définition en langue d'origine."},{"q":"Pourquoi le mode console est-il important ?","a":"Parce que certaines pages perturbent les injections inline dans le DOM. Vous pouvez y basculer soit en acceptant la détection proposée par l'extension, soit en cliquant sur repair, l'icône outil dans un tooltip. Le mode console conserve alors la partie utile, les définitions stockées, même quand la page est difficile."},{"q":"Peut-on régler l'apparence des tooltips ?","a":"Oui. Dans le popup de l'extension, vous pouvez choisir la couleur des tooltips, ajuster leur opacité avec le curseur prévu pour cela et désactiver la détection automatique de langue si vous préférez garder la main sur le dictionnaire actif."},{"q":"Y a-t-il beaucoup de technique derrière ?","a":"Oui, volontairement. Fournisseurs de repli, candidats de recherche plus intelligents, routage audio, heuristiques de conversion et contournements spécifiques aux navigateurs servent à garder le geste visible très simple."},{"q":"Est-ce que cela fonctionne partout ?","a":"Presque partout, mais pas sur les pages restreintes par le navigateur lui-même, par exemple les stores d'extensions ou d'autres surfaces privilégiées où les content scripts sont bloqués."}]},"footer":"Pas de pubs, pas de traceurs, beaucoup de soin, et une grande quantité de cas limites navigateur gérés de façon transparente."}},"es":{"lang":"es","meta":{"title":"Not A Translator - Definiciones en el idioma original dentro de la p&#225;gina","description":"Definiciones en la lengua de origen, audio, conversiones de unidades y zonas horarias, b&#250;squedas m&#225;s inteligentes y modo consola para p&#225;ginas dif&#237;ciles."},"shared":{"appName":"Not A Translator","lookup":"Obtener significado para","consoleMode":"Modo consola","tooltipMode":"Modo tooltip","contribute":"Contribuir","dictionary":"Diccionario","badges":{"risky":"arriesgado","conditional":"funciona bajo condiciones","ok":"ok"},"console":{"copy":"Copiar","remove":"Eliminar","forceForSite":"Forzar la consola para este sitio"},"languages":{"english":"Ingl&#233;s","spanish":"Espa&#241;ol","french":"Franc&#233;s","german":"Alem&#225;n","italian":"Italiano","finnish":"Finland&#233;s","ancient":"Lat&#237;n + griego (traducci&#243;n)"}},"site":{"languageLabel":"Idioma","brandTagline":"Las definiciones permanecen dentro del flujo de lectura.","nav":{"features":"Funciones","updates":"Novedades","engine":"Motor","usage":"Uso","faq":"FAQ"},"hero":{"eyebrow":"Leer primero. Traducir despu&#233;s si hace falta.","title":"Mantener la definici&#243;n dentro de la p&#225;gina, en la lengua que le pertenece a la palabra.","lead":"Not A Translator inyecta tooltips ligeros cerca de la selecci&#243;n, deja la definici&#243;n original en primer plano y esconde mucha t&#233;cnica detr&#225;s de un gesto muy simple.","primaryCta":"Ver funcionalidades","secondaryCta":"Uso","storeCtas":{"install":"","chrome":"Chrome","firefoxAndroid":"Ffox Android","firefox":"Firefox","paypal":"Contribuir","paypalLabel":"PayPal"},"panelNote":"El modo consola conserva las entradas cuando una p&#225;gina se resiste al renderizado inline.","status":{"published":{"kicker":"Publicado ahora","title":"Disponible en Chrome, Firefox y Firefox Android.","body":"La aplicación ya se distribuye en las principales plataformas actuales."},"funding":{"kicker":"Extensión Safari","title":"El port a Safari está en desarrollo, pero necesita financiación para llegar a publicarse en la Apple Store.","body":"La migración del código existe, el trabajo específico del navegador está hecho y una financiación ayudaría a cruzar la última etapa.","cta":"Apoyar el desarrollo"}},"points":["Las definiciones permanecen en la lengua de origen en lugar de romper la lectura con un desvío genérico de traducción. Ninguna pestaña nueva rompe la lectura. Ningún cambio de idioma interrumpe la comprensión.","Audio, traducir de todos modos, reparaci&#243;n y apertura de p&#225;gina siguen disponibles dentro del tooltip o de la entrada de consola.","Detrás hay mucho trabajo: reintentos de búsqueda, rutas de candidatos, proveedores de reserva y salvaguardas por sitio, detección de las lenguas implicadas y de las páginas refractarias a las inyecciones."],"inlineDemo":{"before":"Not A Translator inyecta ","word":"tooltips","badge":"rotativos","definition":"(sust.) cuadros de definici&#243;n flotantes que permanecen cerca de la selecci&#243;n y pueden girar a su alrededor para escapar de los bordes y los solapamientos.","after":" ligeros cerca de su selección, mantiene la definición en la lengua de origen lo más cerca posible del texto, sin perturbar la comprensión, y esconde mucha tecnicidad detrás de un gesto muy simple."}},"demo":{"word":"epoch","time":"09:58:47","definition":"(sust.) periodo largo de tiempo, especialmente marcado por acontecimientos o un desarrollo particular."},"signals":{"items":[{"value":"3 builds publicados","label":"Disponibles hoy","body":"Chrome, Firefox desktop y Firefox Android son las extensiones actualmente publicadas."},{"value":"Modo consola","label":"Para p&#225;ginas dif&#237;ciles","body":"Cuando una p&#225;gina complica el renderizado del tooltip, las definiciones almacenadas pasan a una consola lateral controlada."},{"value":"B&#250;squeda m&#225;s fina","label":"Detr&#225;s del tooltip","body":"Rescate de candidatos, expresiones de varias palabras y manejo de compuestos mejoran discretamente el resultado visible."}]},"manifesto":{"eyebrow":"Por qu&#233; se siente distinto","title":"No es un flujo traducci&#243;n primero. Es un flujo lectura primero.","lead":"La extensión está diseñada para mantener la página en el centro de la experiencia: definir en el sitio, traducir solo cuando sea necesario y seguir siendo legible incluso cuando la inyección se vuelve difícil.","items":[{"title":"La definici&#243;n antes que la traducci&#243;n","body":"La extensión está pensada para preservar la idea de que una palabra suele entenderse de forma más intuitiva cuando su definición se da primero en su propia lengua."},{"title":"Publicado donde ya importa","body":"Tooltip, quick translate, audio y apertura de página permanecen cerca de la selección para evitar que la lectura se convierta inmediatamente en navegación entre pestañas. ¡Se conserva el hilo!"},{"title":"Cuando la página resiste, el resultado debe sobrevivir","body":"Algunas páginas son hostiles a las inyecciones inline o simplemente inestables. El modo consola existe para que lo esencial, la definición almacenada, siga disponible en lugar de desaparecer con el tooltip. En el peor de los casos, F5/refresh devolverá la página a su estado inicial. Ninguna modificación es permanente a este nivel."}]},"screenshots":{"eyebrow":"En situaci&#243;n","title":"La extensi&#243;n est&#225; pensada para vivir dentro de situaciones reales de lectura.","lead":"Una vista Firefox desktop y una vista Safari iPhone en desarrollo ayudan a volver eso concreto.","desktop":{"title":"Firefox desktop","body":"Tooltip cerca de la palabra seleccionada, controles del popup y el flujo de lectura original conservado."},"mobile":{"title":"Build Safari iPhone en desarrollo","body":"Una disposici&#243;n port&#225;til donde el tooltip sigue siendo compacto y legible dentro de una p&#225;gina m&#243;vil."}},"features":{"eyebrow":"Funciones clave","title":"Simple en uso, t&#233;cnico en segundo plano.","lead":"Una sola selección puede activar el enrutado de diccionarios, búsquedas de respaldo, definiciones de nuevos candidatos sobre formas variantes, fuentes de audio, parsing de conversiones, interpretación de zonas horarias y, en páginas hostiles, un cambio controlado al modo consola.","items":[{"title":"Definiciones en la lengua original","body":"La idea principal sigue siendo la misma: seleccionar una palabra y obtener su definici&#243;n en su propia lengua para mantener unidas la lectura y el aprendizaje."},{"title":"Conversiones y zonas horarias","body":"Las selecciones num&#233;ricas pueden pasar al modo conversi&#243;n, incluidas unidades y horas con zona horaria reconocida, sin salir de la p&#225;gina."},{"title":"Audio cerca de la selecci&#243;n","body":"Cuando existe pronunciación, el tooltip o la entrada de consola puede exponer el audio directamente usando la mejor fuente disponible. el icono indica si la voz es humana o sintética"},{"title":"Modo consola para p&#225;ginas hostiles","body":"El clic en la acción repair abre ahora directamente el modo consola. todas las demás reparaciones se tratan automáticamente antes. Cuando el renderizado inline no es fiable, las entradas siguen siendo legibles en un panel controlado en vez de perderse."},{"title":"Rutas de b&#250;squeda m&#225;s inteligentes","body":"Las b&#250;squedas ahora dependen de un enrutado de candidatos m&#225;s robusto: forma exacta primero, luego rescates, expresiones de varias palabras y estrategias de lema o compuesto cuando conviene."},{"title":"Mucha t&#233;cnica, discretamente","body":"Quick translate ahora sustituye la definici&#243;n directamente dentro del tooltip. Proxys de traducci&#243;n, reservas, ajustes m&#243;viles y protecciones por sitio mantienen ese flujo compacto."}]},"updates":{"eyebrow":"Mejoras recientes","title":"La web ya refleja el estado real de la extensi&#243;n.","lead":"La p&#225;gina de presentaci&#243;n describe por fin la versi&#243;n actual en lugar de una instant&#225;nea antigua.","items":[{"kicker":"Conversi&#243;n","title":"Lectura correcta de n&#250;meros grandes","body":"Selecciones como &#8220;12,333 feet&#8221; e incluso &#8220;12,333,425 feet&#8221; se interpretan ahora como miles agrupados y no como n&#250;meros decimales."},{"kicker":"Hora","title":"Las zonas horarias siguen formando parte del mismo gesto","body":"Una selecci&#243;n horaria puede abrir un tooltip dedicado cuando se reconoce una zona horaria, en lugar de obligar a un flujo aparte."},{"kicker":"Diccionario","title":"El fin&#233;s entra en el conjunto activo","body":"El fin&#233;s ya forma parte de la l&#237;nea viva, con diccionario, men&#250;, i18n y la fontaner&#237;a de audio / b&#250;squeda asociada."},{"kicker":"B&#250;squeda","title":"Nuevos modos de b&#250;squeda bajo el cap&#243;","body":"El trabajo reciente mejora el rescate de expresiones inglesas de varias palabras y a&#241;ade un manejo m&#225;s s&#243;lido de compuestos finlandeses cuando la b&#250;squeda directa no basta."}]},"engine":{"eyebrow":"Bajo el cap&#243;","title":"Suceden muchas m&#225;s cosas de las que deja ver la interfaz.","lead":"La extensi&#243;n es deliberadamente ligera en apariencia y muy activa en segundo plano.","items":[{"title":"Enrutado de candidatos","body":"Una b&#250;squeda no se detiene en una sola forma bruta. El motor puede reintentar formas exactas, variantes de rescate y candidatos de varias palabras antes de rendirse."},{"title":"Conversiones que leen texto real","body":"La ruta de conversi&#243;n trata ahora con m&#225;s seguridad los miles agrupados y puede decidir entre unidad y zona horaria a partir de la misma selecci&#243;n."},{"title":"Reserva en consola","body":"El control repair act&#250;a ahora como un verdadero cambio de modo: env&#237;a la b&#250;squeda actual al modo consola en lugar de limitarse a una recuperaci&#243;n cosm&#233;tica."},{"title":"Suministro de audio","body":"La pronunciaci&#243;n puede venir de Wiktionary, Commons, DWDS o de una reserva generada seg&#250;n diccionario y disponibilidad."},{"title":"Trabajo espec&#237;fico para fin&#233;s","body":"El fin&#233;s no es solo otra entrada de men&#250;: a&#241;ade enrutado de diccionarios y estrategias de compuestos detr&#225;s del tel&#243;n."},{"title":"Pista de fiabilidad por sitio","body":"El badge no est&#225; solo para mostrar una lengua. Tambi&#233;n debe comunicar confianza, incluso en p&#225;ginas restringidas u hostiles."},{"title":"Compatibilidad smartphone","body":"La web de presentaci&#243;n mantiene ahora la misma jerarqu&#237;a en pantallas peque&#241;as: acciones apiladas, botones a lo ancho y tarjetas legibles en lugar de un escritorio comprimido."}]},"usage":{"eyebrow":"Uso","title":"Un gesto corto que intenta preservar la lectura.","lead":"La extensi&#243;n intenta mantener el contexto, evitar navegaci&#243;n innecesaria y degradarse con elegancia cuando una p&#225;gina interfiere con la inyecci&#243;n.","steps":["Seleccione una palabra o una expresi&#243;n en la p&#225;gina que est&#225; leyendo.","Use la acci&#243;n de la extensi&#243;n o el men&#250; contextual para pedir la definici&#243;n.","Lea el tooltip junto a la selecci&#243;n y permanezca dentro de la p&#225;gina para la definici&#243;n, el audio, quick translate o la apertura de p&#225;gina si hace falta.","Si la detecci&#243;n del sitio propone el modo consola, responda OK para cambiar. Tambi&#233;n puede hacer clic en repair, el icono de herramienta dentro de un tooltip, para enviar esa b&#250;squeda a la consola.","El modo consola conserva las entradas almacenadas en un panel lateral estable cuando el renderizado inline se vuelve poco fiable.","Para ajustar el color y la opacidad de los tooltips, o desactivar la detecci&#243;n autom&#225;tica del idioma, abra el popup de la extensi&#243;n: all&#237; est&#225;n el color actual, la paleta disponible, el control deslizante de opacidad y el interruptor de autodetecci&#243;n de idioma."]},"platforms":{"title":"Plataformas","items":["Publicado: Firefox desktop","Publicado: Chrome desktop","Publicado: Firefox Android","Safari est&#225; en desarrollo activo y necesita financiaci&#243;n para llegar a la publicaci&#243;n."]},"dictionaries":{"title":"Diccionarios","items":["Ingl&#233;s - Merriam-Webster Learner's Dictionary","Espa&#241;ol - Diccionario de la Lengua Espa&#241;ola","Franc&#233;s - Larousse","Alem&#225;n - DWDS","Italiano - De Mauro Internazionale","Fin&#233;s - Kielitoimiston sanakirja con reserva en Wiktionary","Lat&#237;n + griego - ruta orientada a traducci&#243;n para lenguas antiguas"]},"faq":{"eyebrow":"FAQ","title":"Algunas cosas que conviene decir con claridad.","items":[{"q":"&#191;Es una extensi&#243;n de traducci&#243;n autom&#225;tica?","a":"No. La traducci&#243;n existe como recurso opcional. La idea principal sigue siendo mostrar primero la definici&#243;n en la lengua original."},{"q":"&#191;Por qu&#233; es importante el modo consola?","a":"Porque algunas p&#225;ginas interfieren con las inyecciones inline en el DOM. Puede entrar aceptando la detecci&#243;n propuesta por la extensi&#243;n o haciendo clic en repair, el icono de herramienta dentro de un tooltip. El modo consola conserva la parte &#250;til, las definiciones almacenadas, incluso cuando la p&#225;gina es dif&#237;cil."},{"q":"&#191;Se puede ajustar el aspecto de los tooltips?","a":"S&#237;. En el popup de la extensi&#243;n puede elegir el color de los tooltips, ajustar la opacidad con el control deslizante dedicado y desactivar la detecci&#243;n autom&#225;tica del idioma si prefiere mantener el control sobre el diccionario activo."},{"q":"&#191;Hay mucha t&#233;cnica detr&#225;s?","a":"S&#237;, a prop&#243;sito. Proveedores de reserva, candidatos de b&#250;squeda m&#225;s inteligentes, rutas de audio, heur&#237;sticas de conversi&#243;n y soluciones espec&#237;ficas del navegador sirven para mantener el gesto visible muy simple."},{"q":"&#191;Funciona en todas partes?","a":"Casi en todas partes, pero no en p&#225;ginas restringidas por el propio navegador, por ejemplo las tiendas de extensiones u otras superficies privilegiadas donde los content scripts est&#225;n bloqueados."}]},"footer":"Sin anuncios, sin rastreadores, mucho cuidado y una gran cantidad de casos límite de navegador gestionados de forma transparente."}},"de":{"lang":"de","meta":{"title":"Not A Translator - Definitionen in der Ursprungssprache direkt auf der Seite","description":"Definitionen in der Ursprungssprache, Audio, Einheiten- und Zeitzonen-Umrechnungen, intelligentere Suchpfade und Konsolenmodus für schwierige Seiten."},"shared":{"appName":"Not A Translator","lookup":"Bedeutung suchen für","consoleMode":"Konsolenmodus","tooltipMode":"Tooltip-Modus","contribute":"Beitragen","dictionary":"Wörterbuch","badges":{"risky":"riskant","conditional":"funktioniert unter Bedingungen","ok":"ok"},"console":{"copy":"Kopieren","remove":"Entfernen","forceForSite":"Konsolenmodus für diese Seite erzwingen"},"languages":{"english":"Englisch","spanish":"Spanisch","french":"Französisch","german":"Deutsch","italian":"Italienisch","finnish":"Finnisch","ancient":"Latein + Griechisch (�obersetzung)"}},"site":{"languageLabel":"Sprache","brandTagline":"Definitionen bleiben im Lesefluss.","nav":{"features":"Funktionen","updates":"Neuheiten","engine":"Engine","usage":"Verwendung","faq":"FAQ"},"hero":{"eyebrow":"Erst lesen. Dann übersetzen, wenn nötig.","title":"Die Definition auf der Seite behalten, in der Sprache, zu der das Wort gehört.","lead":"Not A Translator fügt leichte Tooltips nahe an Ihrer Auswahl ein, hält die Definition in der Ursprungssprache im Vordergrund und versteckt viel Technik hinter einer sehr einfachen Geste.","primaryCta":"Funktionalitäten ansehen","secondaryCta":"Nutzung","storeCtas":{"install":"","chrome":"Chrome","firefoxAndroid":"Ffox Android","firefox":"Firefox","paypal":"PayPal Me","paypalLabel":""},"panelNote":"Der Konsolenmodus bewahrt Einträge, wenn eine Seite das Tooltip-Rendering stört.","status":{"published":{"kicker":"Jetzt veröffentlicht","title":"Verfügbar für Chrome, Firefox und Firefox Android.","body":"Die Anwendung wird bereits auf den wichtigsten aktuellen Plattformen verteilt."},"funding":{"kicker":"Safari-Erweiterung","title":"Die Safari-Portierung ist in Entwicklung, braucht aber Finanzierung bis zur Veröffentlichung im Apple Store.","body":"Die Code-Migration existiert, die browserspezifische Arbeit ist gemacht, und Finanzierung würde helfen, den letzten Schritt zu schaffen.","cta":"Entwicklung unterstützen"}},"points":["Definitionen bleiben in der Ausgangssprache, statt das Lesen durch einen allgemeinen Übersetzungsumweg zu unterbrechen. Kein neuer Tab unterbricht das Lesen. Kein Sprachwechsel unterbricht das Verständnis.","Audio, trotzdem übersetzen, Reparatur und Seitenöffnung bleiben direkt im Tooltip oder im Konsoleneintrag erreichbar.","Hinter den Kulissen passiert viel: Suchwiederholungen, Kandidaten-Routing, Fallback-Anbieter und Schutzmechanismen pro Website, Erkennung der beteiligten Sprachen und von Seiten, die sich gegen Injektionen sperren."],"inlineDemo":{"before":"Not A Translator fügt leichte ","word":"Tooltips","badge":"rotierend","definition":"(Subst.) schwebende Definitionsfelder, die nahe an der Auswahl bleiben und sich um sie drehen k�nnen, um R�ndern und �berlappungen auszuweichen.","after":" nahe an Ihrer Auswahl ein, hält die Definition in der Ursprungssprache möglichst nah am Text, ohne Ihr Verständnis zu stören, und verbirgt viel technische Komplexität hinter einer sehr einfachen Geste."}},"demo":{"word":"epoch","time":"09:58:47","definition":"(Subst.) ein langer Zeitraum, besonders einer, der durch bestimmte Ereignisse oder Entwicklungen geprägt ist."},"signals":{"items":[{"value":"3 veröffentlichte Builds","label":"Heute verfügbar","body":"Chrome, Firefox Desktop und Firefox Android sind die derzeit veröffentlichten Erweiterungen."},{"value":"Konsolenmodus","label":"Für schwierige Seiten","body":"Wenn eine Seite das Tooltip-Rendering stört, wechseln gespeicherte Definitionen in eine kontrollierte Seitenkonsole."},{"value":"Intelligentere Suche","label":"Hinter dem Tooltip","body":"Kandidatenrettung, Mehrwortsuche und Kompositabehandlung verbessern unauffällig das sichtbare Ergebnis."}]},"manifesto":{"eyebrow":"Warum es sich anders anfühlt","title":"Ein Lesen-zuerst-Ablauf.","lead":"Die Erweiterung ist darauf ausgelegt, die Seite im Zentrum der Erfahrung zu lassen: direkt auf der Seite definieren, nur bei Bedarf übersetzen und lesbar bleiben, auch wenn die Injection schwierig wird.","items":[{"title":"Definition vor �obersetzung","body":"Die Erweiterung soll die Idee bewahren, dass ein Wort oft intuitiver verstanden wird, wenn seine Definition zuerst in seiner eigenen Sprache gegeben wird."},{"title":"Die Seite bleibt die Hauptfläche","body":"Tooltip, Quick Translate, Audio und Seitenöffnung bleiben nahe an der Auswahl, damit Lesen nicht sofort zu Tab-Wechseln wird. Der rote Faden bleibt erhalten!"},{"title":"Wenn die Seite sich wehrt, muss das Ergebnis überleben","body":"Manche Seiten sind feindlich gegenüber Inline-Injections oder schlicht instabil. Der Konsolenmodus sorgt dafür, dass das Wesentliche, die gespeicherte Definition, verfügbar bleibt, statt mit dem Tooltip zu verschwinden. Im schlimmsten Fall setzt F5/Refresh die Seite wieder in ihren Ausgangszustand zurück. Auf dieser Ebene ist keine Änderung dauerhaft."}]},"screenshots":{"eyebrow":"Im Einsatz","title":"Die Erweiterung ist dafür gemacht, in echten Lesesituationen zu leben.","lead":"Eine Firefox-Desktop-Ansicht und eine Safari-iPhone-Entwicklungsansicht machen das greifbarer.","desktop":{"title":"Firefox Desktop","body":"Tooltip nahe am ausgewählten Wort, Popup-Steuerung und ursprünglicher Lesefluss bleiben erhalten."},"mobile":{"title":"Safari iPhone Entwicklungs-Build","body":"Ein mobiles Layout, in dem der Tooltip kompakt und lesbar innerhalb einer mobilen Seite bleibt."}},"features":{"eyebrow":"Kernfunktionen","title":"An der Oberfläche einfach, darunter dicht.","lead":"Eine einzige Auswahl kann Wörterbuch-Routing, Ersatzsuchen, Definitionen neuer Kandidaten auf Variantenformen, Audioquellen, Umrechnungs-Parsing, Zeitzonen-Interpretation und auf feindlichen Seiten einen kontrollierten Wechsel in den Konsolenmodus auslösen.","items":[{"title":"Definitionen in der Ursprungssprache","body":"Der Hauptpfad bleibt dieselbe Idee: ein Wort auswählen und seine Definition in der Sprache erhalten, zu der es gehört, damit Lesen und Sprachenlernen verbunden bleiben."},{"title":"Umrechnungen und Zeitzonenhilfen","body":"Numerische Auswahlen können in den Umrechnungsmodus wechseln, einschlie�Ylich Einheiten und zeitzonenbezogener Uhrzeiten, ohne die Seite zu verlassen."},{"title":"Audio nahe an der Auswahl","body":"Wenn eine Aussprache verfügbar ist, kann der Tooltip oder der Konsoleneintrag Audio direkt bereitstellen und die beste verfügbare Quelle wählen. Das Symbol zeigt an, ob die Stimme menschlich oder synthetisch ist"},{"title":"Konsolenmodus für feindliche Seiten","body":"Die Aktion repair öffnet jetzt direkt den Konsolenmodus. Alle anderen Reparaturen werden vorher automatisch behandelt. Wenn Inline-Rendering unzuverlässig wird, bleiben die Einträge in einem kontrollierten Panel lesbar, statt verloren zu gehen."},{"title":"Intelligentere Suchpfade","body":"Die Suche stützt sich jetzt auf robusteres Kandidaten-Routing: zuerst die exakte Form, dann gerettete Kandidaten, Mehrwortausdrücke sowie Lemma- oder Kompositastrategien, wenn sie nützlich sind."},{"title":"Viel Technik, leise","body":"Quick Translate ersetzt jetzt die Definition direkt im Tooltip. Dahinter stehen Fallback-Anbieter, Schutzmechanismen pro Website, mobile Positionierungsarbeit und browserspezifische Workarounds, damit die Interaktion kurz bleibt."}]},"updates":{"eyebrow":"Jüngste Verbesserungen","title":"Die Website spiegelt jetzt den realen Stand der Erweiterung wider.","lead":"Die Präsentationsseite beschreibt endlich die aktuelle Version statt eines älteren Schnappschusses.","items":[{"kicker":"Umrechnung","title":"Korrekte Auswertung gro�Yer Zahlen","body":"Auswahlen wie �?z12,333 feet�?o oder sogar �?z12,333,425 feet�?o werden jetzt als Tausendergruppen statt als Dezimalzahlen interpretiert."},{"kicker":"Zeit","title":"Zeitzonen bleiben Teil derselben Geste","body":"Eine Uhrzeit-Auswahl kann ein eigenes Tooltip öffnen, wenn eine Zeitzone erkannt wird, statt einen getrennten Ablauf zu erzwingen."},{"kicker":"Wörterbuch","title":"Finnisch gehört jetzt zum aktiven Satz","body":"Finnisch ist jetzt Teil der lebendigen Auswahl, mit Wörterbuchzugang, Menüeinträgen sowie der zugehörigen Audio- und Suchlogik."},{"kicker":"Suche","title":"Neue Suchpfade unter dem Tooltip","body":"Neuere Sucharbeit verbessert die Kandidatenrettung für englische Mehrwortausdrücke und stärkt die Kompositabehandlung für Finnisch, wenn die Direktsuche nicht reicht."}]},"engine":{"eyebrow":"Unter der Haube","title":"Es passiert viel mehr, als die Oberfläche erkennen lässt.","lead":"Die Erweiterung wirkt absichtlich leicht und ist im Hintergrund sehr aktiv.","items":[{"title":"Kandidaten-Routing","body":"Eine Suche endet nicht bei einer rohen Form. Die Engine kann exakte Formen, gerettete Varianten und Mehrwortkandidaten erneut versuchen, bevor sie aufgibt."},{"title":"Umrechnungen, die echten Text lesen","body":"Der Umrechnungspfad behandelt Tausendergruppen jetzt sicherer und kann aus derselben Auswahl zwischen Einheit und Zeitzone unterscheiden."},{"title":"Konsolen-Fallback","body":"Die repair-Steuerung wirkt jetzt wie ein echter Moduswechsel: Sie schickt die aktuelle Suche in den Konsolenmodus statt nur eine kosmetische Reparatur zu versuchen."},{"title":"Audioquellen","body":"Aussprache kann je nach Wörterbuch und Verfügbarkeit aus Wiktionary, Commons, DWDS oder einem generierten Fallback kommen."},{"title":"Finnisch-spezifische Arbeit","body":"Finnisch ist nicht nur ein weiterer Menüeintrag: Dahinter stehen eigenes Wörterbuch-Routing und kompositaorientierte Strategien."},{"title":"Hinweise zur Zuverlässigkeit pro Website","body":"Das Badge soll nicht nur Sprache anzeigen. Es soll auch Vertrauen vermitteln, auch auf eingeschränkten oder feindlichen Seiten."},{"title":"Smartphone-Kompatibilität","body":"Die Präsentationsseite behält jetzt dieselbe Hierarchie auf kleinen Bildschirmen: gestapelte Aktionen, Buttons über die volle Breite und lesbare Karten statt einer gequetschten Desktop-Ansicht."}]},"usage":{"eyebrow":"Verwendung","title":"Eine kurze Geste, die das Lesen bewahren will.","lead":"Die Erweiterung versucht, den Kontext zu erhalten, unnötige Navigation zu vermeiden und sich sauber zurückzunehmen, wenn eine Seite die Injection stört.","steps":["Wählen Sie ein Wort oder einen Ausdruck auf der Seite aus, die Sie gerade lesen.","Nutzen Sie die Aktion der Erweiterung oder das Kontextmenü, um die Definition anzufordern.","Lesen Sie den Tooltip nahe an der Auswahl und bleiben Sie für Definition, Audio, Quick Translate oder das �-ffnen der Seite in der Seite.","Wenn die Website-Erkennung den Konsolenmodus vorschlägt, antworten Sie mit OK, um zu wechseln. Sie können auch auf repair, das Werkzeugsymbol im Tooltip, klicken, um diese Suche in die Konsole zu schicken.","Der Konsolenmodus hält gespeicherte Einträge in einem stabilen Seitenpanel, wenn Inline-Rendering unzuverlässig wird.","Um Tooltip-Farbe und Opazität einzustellen oder die automatische Spracherkennung zu deaktivieren, öffnen Sie das Popup der Erweiterung: Dort finden Sie die aktuelle Farbe, die verfügbare Palette, den Opazitätsregler und den Schalter für die Sprachautodetektion."]},"platforms":{"title":"Plattformen","items":["Veröffentlicht: Firefox Desktop","Veröffentlicht: Chrome Desktop","Veröffentlicht: Firefox Android","Safari befindet sich in aktiver Entwicklung und braucht Finanzierung bis zur Veröffentlichung."]},"dictionaries":{"title":"Wörterbücher","items":["Englisch - Merriam-Webster Learner's Dictionary","Spanisch - Diccionario de la Lengua Española","Französisch - Larousse","Deutsch - DWDS","Italienisch - De Mauro Internazionale","Finnisch - Kielitoimiston sanakirja / Wiktionary-Fallback","Latein + Griechisch - übersetzungsorientierter Pfad für antike Sprachen"]},"faq":{"eyebrow":"FAQ","title":"Ein paar Dinge, die klar gesagt werden sollten.","items":[{"q":"Ist das eine maschinelle �obersetzungserweiterung?","a":"Nein. �obersetzung existiert als optionaler Rückweg. Die Hauptidee bleibt, zuerst die Definition in der Ursprungssprache zu zeigen."},{"q":"Warum ist der Konsolenmodus wichtig?","a":"Weil manche Seiten Inline-DOM-Injections stören. Sie können entweder über den von der Erweiterung vorgeschlagenen Hinweis dorthin wechseln oder auf repair, das Werkzeugsymbol im Tooltip, klicken. Der Konsolenmodus bewahrt dann den nützlichen Teil, die gespeicherten Definitionen, auch wenn die Seite schwierig ist."},{"q":"Kann man das Aussehen der Tooltips anpassen?","a":"Ja. Im Popup der Erweiterung können Sie die Farbe der Tooltips wählen, ihre Opazität mit dem vorgesehenen Regler anpassen und die automatische Spracherkennung deaktivieren, wenn Sie das aktive Wörterbuch lieber selbst steuern möchten."},{"q":"Passiert im Hintergrund viel Technik?","a":"Ja, absichtlich. Fallback-Anbieter, intelligentere Suchkandidaten, Audio-Routing, Umrechnungsheuristiken und browserspezifische Workarounds sorgen dafür, dass die sichtbare Geste einfach bleibt."},{"q":"Funktioniert das überall?","a":"Fast überall, aber nicht auf Seiten, die vom Browser selbst eingeschränkt werden, etwa Erweiterungs-Stores oder andere privilegierte Flächen, auf denen Content-Skripte blockiert sind."}]},"footer":"Keine Werbung, keine Tracker, viel Sorgfalt und viele browser-spezifische Grenzfälle, die transparent abgefangen werden."}},"fi":{"lang":"fi","meta":{"title":"Not A Translator - Määritelmät alkuperäiskielellä suoraan sivulla","description":"Alkuperäiskieliset määritelmät, ääni, yksikkö- ja aikavyöhykemuunnokset, älykkäämmät haut ja konsolitila vaikeille sivuille."},"shared":{"appName":"Not A Translator","lookup":"Hae sanan merkitys","consoleMode":"Konsolitila","tooltipMode":"Työkaluvihjetila","contribute":"Osallistu","dictionary":"Sanakirja","badges":{"risky":"riskialtis","conditional":"toimii tietyissä oloissa","ok":"ok"},"console":{"copy":"Kopioi","remove":"Poista","forceForSite":"Pakota konsoli tälle sivustolle"},"languages":{"english":"Englanti","spanish":"Espanja","french":"Ranska","german":"Saksa","italian":"Italia","finnish":"Suomi","ancient":"Latina + kreikka (käännös)"}},"site":{"languageLabel":"Kieli","brandTagline":"Määritelmät pysyvät lukemisen virrassa.","nav":{"features":"Ominaisuudet","updates":"Uutta","engine":"Moottori","usage":"Käyttö","faq":"UKK"},"hero":{"eyebrow":"Lue ensin. Käännö vasta tarvittaessa.","title":"Pidä määritelmä sivulla, sillä kielellä jolle sana kuuluu.","lead":"Not A Translator lisää kevyet työkaluvihjeet valinnan lähelle, nostaa alkuperäiskielisen määritelmän etusijalle ja piilottaa paljon tekniikkaa hyvin yksinkertaisen eleen taakse.","primaryCta":"Katso toiminnallisuudet","secondaryCta":"Käyttö","storeCtas":{"install":"","chrome":"Chrome","firefoxAndroid":"Ffox Android","firefox":"Firefox","paypal":"Osallistu","paypalLabel":"PayPal"},"panelNote":"Konsolitila säilyttää merkinnät, kun sivu vastustaa työkaluvihjeiden renderöintiä.","status":{"published":{"kicker":"Julkaistu nyt","title":"Saatavilla Chromelle, Firefoxille ja Firefox Androidille.","body":"Sovellus on jo saatavilla tämän hetken tärkeimmillä alustoilla."},"funding":{"kicker":"Safari-laajennus","title":"Safari-porttaus on kehityksessä, mutta tarvitsee rahoitusta julkaisuun Apple Storessa.","body":"Koodin migraatio on olemassa, selainkohtainen työ on tehty, ja rahoitus auttaisi viemään viimeisen vaiheen läpi.","cta":"Tue kehitystä"}},"points":["Määritelmät pysyvät lähdekielellä sen sijaan, että lukeminen katkeaisi yleiseen käännöskierrokseen. Ei uutta välilehteä katkaisemaan lukemista. Ei kielenvaihtoa häiritsemään ymmärtämistä.","Ääni, käännä silti, korjaus ja sivun avaus pysyvät yhden napsautuksen päässä työkaluvihjeessä tai konsolimerkinnässä.","Kulissien takana tapahtuu paljon: hakujen uusintayrityksiä, ehdokasreititystä, varapalveluja ja sivustokohtaisia suojauksia, mukana olevien kielten tunnistusta sekä injektioita vastustavien sivujen tunnistusta."],"inlineDemo":{"before":"Not A Translator lisää kevyet ","word":"tooltipit","badge":"kiertyvät","definition":"(subst.) kelluvat määritelmälaatikot, jotka pysyvät valinnan lähellä ja voivat kiertää sen ympäri väistääkseen reunoja ja päällekkäisyyksiä.","after":" valinnan lähelle, pitää lähdekielisen määritelmän mahdollisimman lähellä tekstiä häiritsemättä ymmärtämistäsi ja piilottaa paljon teknistä monimutkaisuutta hyvin yksinkertaisen eleen taakse."}},"demo":{"word":"epoch","time":"09:58:47","definition":"(subst.) pitkä ajanjakso, jota leimaavat tietyt tapahtumat tai kehitys."},"signals":{"items":[{"value":"3 julkaistua buildiä","label":"Saatavilla nyt","body":"Chrome, Firefox desktop ja Firefox Android ovat tällä hetkellä julkaistut laajennukset."},{"value":"Konsolitila","label":"Vaikeille sivuille","body":"Kun sivu sotkee työkaluvihjeen renderöintiä, tallennetut määritelmät siirtyvät hallittuun sivukonsoliin."},{"value":"Älykkäämpi haku","label":"Työkaluvihjeen takana","body":"Ehdokkaiden pelastusreitit, monisanaiset haut ja yhdysrakenteiden käsittely parantavat näkyvää tulosta hiljaa."}]},"manifesto":{"eyebrow":"Miksi tämä tuntuu erilaiselta","title":"Ei käännös ensin -työnkulku. Vaan luku ensin -työnkulku.","lead":"Laajennus on suunniteltu pitämään sivu kokemuksen keskiössä: määritellä paikalla, kääntää vain tarvittaessa ja pysyä luettavana myös silloin, kun injektio vaikeutuu.","items":[{"title":"Määritelmä ennen käännöstä","body":"Laajennus on suunniteltu säilyttämään ajatus siitä, että sana ymmärretään usein intuitiivisemmin, kun sen määritelmä annetaan ensin sen omalla kielellä."},{"title":"Julkaistu siellä missä sillä jo on merkitystä","body":"Tooltip, quick translate, ääni ja sivun avaaminen pysyvät lähellä valintaa, jotta lukeminen ei muutu heti välilehtien välillä siirtyilyksi. Ajatus säilyy mukana!"},{"title":"Kun sivu vastustaa, tuloksen täytyy säilyä","body":"Jotkin sivut ovat vihamielisiä inline-injektioille tai yksinkertaisesti epävakaita. Konsolitila on olemassa, jotta olennainen osa, tallennettu määritelmä, pysyy saatavilla eikä katoa työkaluvihjeen mukana. Pahimmassa tapauksessa F5/refresh palauttaa sivun alkuperäiseen tilaansa. Mikään muutos ei ole tällä tasolla pysyvä."}]},"screenshots":{"eyebrow":"Käytännössä","title":"Laajennus on tarkoitettu elämään aidoissa lukutilanteissa.","lead":"Firefox desktop -näkymä ja Safari iPhone -kehitysnäkymä tekevät siitä konkreettisen.","desktop":{"title":"Firefox desktop","body":"Työkaluvihje valitun sanan lähellä, popup-ohjaimet ja alkuperäinen lukemisen virta säilyvät."},"mobile":{"title":"Safari iPhone -kehitysversio","body":"Kannettava asettelu, jossa työkaluvihje pysyy kompaktina ja luettavana mobiilisivun sisällä."}},"features":{"eyebrow":"Ydinominaisuudet","title":"Käytössä yksinkertainen, taustalla tekninen.","lead":"Yksi valinta voi käynnistää sanakirjareitityksen, varahaut, uusien ehdokkaiden määritelmät varianttimuodoista, äänilähteiden haun, muunnosten parsinnan, aikavyöhykkeiden tulkinnan ja hankalilla sivuilla hallitun siirtymisen konsolitilaan.","items":[{"title":"Alkuperäiskieliset määritelmät","body":"Pääajatus on edelleen sama: valitse sana ja saat sen määritelmän sen omalla kielellä, jotta lukeminen ja oppiminen pysyvät yhdessä."},{"title":"Muunnokset ja aikavyöhykkeet","body":"Numeerinen valinta voi vaihtua muunnostilaan, mukaan lukien yksiköt ja tunnistetut aikavyöhykkeet, ilman että poistut sivulta."},{"title":"Ääni valinnan lähellä","body":"Kun ääntämys on saatavilla, työkaluvihje tai konsolimerkintä voi tarjota äänen suoraan valitsemalla parhaan saatavilla olevan lähteen. kuvake ilmaisee, onko ääni ihmisen vai synteettinen"},{"title":"Konsolitila vaikeille sivuille","body":"Repair-toiminnon napsautus avaa nyt suoraan konsolitilan. kaikki muut korjaukset käsitellään automaattisesti etukäteen. Kun inline-renderöinti ei ole luotettava, merkinnät pysyvät luettavina hallitussa paneelissa katoamisen sijaan."},{"title":"Älykkäämmät hakureitit","body":"Haku nojaa nyt vahvempaan ehdokasreititykseen: tarkka muoto ensin, sitten pelastusreitit, monisanaiset ilmaukset sekä lemma- ja yhdysstrategiat siellä missä niistä on hyötyä."},{"title":"Paljon tekniikkaa, hiljaa","body":"Quick translate vaihtaa nyt määritelmän suoraan työkaluvihjeen sisällä. Käännösproxyt, varapalvelut, mobiilisijoittelu ja sivustokohtaiset suojaukset pitävät tämän virtauksen kompaktina."}]},"updates":{"eyebrow":"Viimeaikaiset parannukset","title":"Sivusto kuvaa nyt laajennuksen todellista nykytilaa.","lead":"Esittelysivu kertoo viimein nykyisestä versiosta eikä vanhasta tilannekuvasta.","items":[{"kicker":"Muunnos","title":"Suurten lukujen oikea tulkinta","body":"Valinnat kuten \"12,333 feet\" ja jopa \"12,333,425 feet\" tulkitaan nyt tuhaterottimiksi eikä desimaaliluvuiksi."},{"kicker":"Aika","title":"Aikavyöhyke pysyy samassa eleessä","body":"Aikavalinta voi avata oman työkaluvihjeensä, kun aikavyöhyke tunnistetaan, sen sijaan että tarvittaisiin erillinen työnkulku."},{"kicker":"Sanakirja","title":"Suomi liittyy aktiiviseen valikoimaan","body":"Suomi kuuluu nyt elävään sanakirjaryhmään menuineen, i18n-tukineen sekä siihen liittyvine ääni- ja hakureitteineen."},{"kicker":"Haku","title":"Uusia hakutapoja konepellin alla","body":"Viimeaikainen työ parantaa englannin monisanaisten ilmausten pelastusreittejä ja lisää vahvemman yhdysrakenteiden käsittelyn suomelle, kun suora haku ei riitä."}]},"engine":{"eyebrow":"Konepellin alla","title":"Paljon enemmän tapahtuu kuin käyttöliittymä näyttää.","lead":"Laajennus on tarkoituksella kevyt ulospäin ja kiireinen taustalla.","items":[{"title":"Ehdokasreititys","body":"Haku ei pysähdy yhteen raakamuotoon. Moottori voi yrittää tarkkoja muotoja, pelastusvariantteja ja monisanaisia ehdokkaita ennen luovuttamista."},{"title":"Muunnokset, jotka lukevat oikeaa tekstiä","body":"Muunnosreitti käsittelee nyt turvallisemmin tuhaterottimet ja voi erottaa yksikön ja aikavyöhykkeen samasta valinnasta."},{"title":"Konsolivara","body":"Repair-ohjain toimii nyt oikeana tilanvaihtona: se lähettää nykyisen haun konsolitilaan pelkän kosmeettisen korjauksen sijaan."},{"title":"Äänilähteet","body":"Ääntämys voi tulla Wiktionarystä, Commonsista, DWDS:stä tai luodusta varalähteestä sanakirjan ja saatavuuden mukaan."},{"title":"Suomikohtainen työ","body":"Suomi ei ole vain yksi valikkorivi lisää: taustalla on omaa sanakirjareititystä ja yhdysstrategioita."},{"title":"Sivukohtainen luotettavuusvihje","body":"Badgen tehtävä ei ole vain näyttää kieltä. Sen pitää viestiä myös luotettavuudesta, myös rajoitetuilla tai hankalilla sivuilla."},{"title":"Älypuhelinyhteensopivuus","body":"Esittelysivusto säilyttää nyt saman hierarkian pienillä näytöillä: pinotut toiminnot, täysleveät painikkeet ja luettavat kortit puristetun desktop-näkymän sijaan."}]},"usage":{"eyebrow":"Käyttö","title":"Lyhyt ele, joka yrittää säilyttää lukemisen.","lead":"Laajennus yrittää säilyttää kontekstin, välttää turhaa siirtyilyä ja heikentyä hallitusti, kun sivu häiritsee injektiota.","steps":["Valitse sana tai ilmaus lukemaltasi sivulta.","Pyydä määritelmä laajennuksen toiminnolla tai kontekstivalikosta.","Lue työkaluvihje valinnan vierestä ja pysy sivulla määritelmän, äänen, quick translaten tai sivun avauksen kanssa tarvittaessa.","Jos sivuston tunnistus ehdottaa konsolitilaa, vastaa OK vaihtaaksesi siihen. Voit myös napsauttaa repair-kuvaketta, työkalukuvaketta tooltipissa, lähettääksesi haun konsoliin.","Konsolitila säilyttää tallennetut merkinnät vakaassa sivupaneelissa, kun inline-renderöinti muuttuu epäluotettavaksi.","Tooltipien väriä ja opasiteettia säädetään laajennuksen popupista. Samasta paikasta voit myös poistaa automaattisen kielentunnistuksen käytöstä: siellä näkyvät nykyinen väri, käytettävissä oleva paletti, opasiteettiliukusäädin ja kielentunnistuksen kytkin."]},"platforms":{"title":"Alustat","items":["Julkaistu: Firefox desktop","Julkaistu: Chrome desktop","Julkaistu: Ffox Android","Safari on aktiivisessa kehityksessä ja tarvitsee rahoitusta julkaisuun asti."]},"dictionaries":{"title":"Sanakirjat","items":["Englanti - Merriam-Webster Learner's Dictionary","Espanja - Diccionario de la Lengua Española","Ranska - Larousse","Saksa - DWDS","Italia - De Mauro Internazionale","Suomi - Kielitoimiston sanakirja ja Wiktionary-varareitti","Latina + kreikka - käännöspainotteinen reitti antiikin kielille"]},"faq":{"eyebrow":"UKK","title":"Muutama asia on hyvä sanoa suoraan.","items":[{"q":"Onko tämä konekäännöslaajennus?","a":"Ei. Käännös on valinnainen varareitti. Pääajatus on edelleen näyttää ensin alkuperäiskielinen määritelmä."},{"q":"Miksi konsolitila on tärkeää","a":"Koska jotkin sivut häiritsevät inline-DOM-injektioita. Voit siirtyä siihen joko hyväksymällä laajennuksen ehdottaman tunnistuksen tai napsauttamalla repair-kuvaketta tooltipissa. Konsolitila säilyttää silloin hyödyllisen osan, tallennetut määritelmät, vaikka sivu olisi vaikea."},{"q":"Voiko tooltipien ulkoasua säätää?","a":"Kyllä. Laajennuksen popupissa voit valita tooltipien värin, säätää opasiteettia omalla liukusäätimellään ja poistaa automaattisen kielentunnistuksen käytöstä, jos haluat pitää aktiivisen sanakirjan itse hallinnassa."},{"q":"Onko taustalla paljon tekniikkaa?","a":"Kyllä, tarkoituksella. Varapalvelut, älykkäämmät hakuehdokkaat, äänireititys, muunnosheuristiikat ja selainkohtaiset kiertotavat pitävät näkyvän eleen silti yksinkertaisena."},{"q":"Toimiiko tämä kaikkialla?","a":"Lähes kaikkialla, mutta ei selaimen itsensä rajoittamilla sivuilla, kuten lisäosakaupoissa tai muissa etuoikeutetuissa näkymissä, joissa sisältöskriptit on estetty."}]},"footer":"Ei mainoksia, ei seurantaa, paljon huolellisuutta ja suuri määrä selainkohtaisia reunatapauksia hoidettuna läpinäkyvästi."}}};
